#include <bits/stdc++.h>
using namespace std;

int main(){
    int m, n;
    if(!(cin >> m >> n)) return 0;
    int row_len; cin >> row_len;
    vector<vector<int>> nums(m, vector<int>(n));
    for(int i = 0; i < m; i++) {
        for(int j = 0; j < n; j++) {
            cin >> nums[i][j];
        }
    }

    for(int i = 0; i < m; i++) {
        for(int j = 0; j < n; j++) {
            bool is_peak = true;
            int val = nums[i][j];
            for(int x = -1; x <= 1; x++) {
                for(int y = -1; y <= 1; y++) {
                    if(abs(x) + abs(y) == 1) {
                        int nx = i + x, ny = j + y;
                        if(nx >= 0 && nx < m && ny >= 0 && ny < n) {
                            if(nums[nx][ny] >= val) {
                                is_peak = false;
                                break;
                            }
                        }
                    }
                }
                if(!is_peak) break;
            }
            if(is_peak) {
                cout << i << ' ' << j << endl;
                return 0;
            }
        }
    }
    return 0;
}
